[DataEventHandler(tableStr(SalesInvoiceTmp), DataEventType::Inserting)]
public static void SalesInvoiceTmp_onInserting(Common sender, DataEventArgs e)
{
    SalesInvoiceTmp salesInvoiceTmp = sender as SalesInvoiceTmp;
    SalesLine salesLineOrg;
    SalesTable salesTable;
    str name;
    InventTable inventTable;

    SalesLine salesLine = SalesLine::findRecId(salesInvoiceTmp.SalesLine);

    InventDim inventDim = InventDim::find(salesLine.InventDimId);

    salesInvoiceTmp.ETGUnitPackSize = inventDim.InventSizeId;

    salesInvoiceTmp.ETGProductName = EcoResProductTranslation::findByProductLanguage(InventTable::find(salesInvoiceTmp.ItemId).Product, SystemParameters::getSystemLanguageId()).Name;

    //}
    //if(curExt() == "C003" || curExt() == "S004")
